import{_ as r,o as e,c as o,a2 as t}from"./chunks/framework.DnrXFDHb.js";const d=JSON.parse('{"title":"Maersk 馬士基（A.P. Møller – Maersk）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/03_全球航商競爭格局/03-2_Maersk_馬士基.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/03_全球航商競爭格局/03-2_Maersk_馬士基.md"}'),i={name:"Deep32Q知識庫/產業洞察/航運產業/03_全球航商競爭格局/03-2_Maersk_馬士基.md"};function n(s,a,l,g,_,h){return e(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="maersk-馬士基-a-p-møller-–-maersk" tabindex="-1">Maersk 馬士基（A.P. Møller – Maersk） <a class="header-anchor" href="#maersk-馬士基-a-p-møller-–-maersk" aria-label="Permalink to &quot;Maersk 馬士基（A.P. Møller – Maersk）&quot;">​</a></h1><h2 id="基本資訊" tabindex="-1">基本資訊 <a class="header-anchor" href="#基本資訊" aria-label="Permalink to &quot;基本資訊&quot;">​</a></h2><ul><li><strong>全球排名</strong>：第2名（第二大貨櫃航運公司）</li><li><strong>總部</strong>：丹麥哥本哈根（Copenhagen, Denmark）</li><li><strong>船隊運力</strong>：約410萬-460萬TEU（2025-2026年）</li><li><strong>戰略定位</strong>：從傳統航運轉型為全方位整合物流供應商</li></ul><h2 id="物流整合戰略" tabindex="-1">物流整合戰略 <a class="header-anchor" href="#物流整合戰略" aria-label="Permalink to &quot;物流整合戰略&quot;">​</a></h2><p>Maersk的核心競爭力不在於單純的貨櫃運力，而在於其端到端供應鏈整合能力：</p><ul><li><strong>物流與服務部門</strong>：2025年該部門EBITDA顯著增長，預計2026年將佔集團總EBITDA的32%</li><li><strong>綜合服務</strong>：涵蓋海運、碼頭營運、內陸運輸（公路/鐵路/航空）、倉儲、清關等全供應鏈服務</li><li><strong>客戶關係</strong>：透過整合物流建立更持久的客戶關係，降低對海運運費波動性的依賴</li><li><strong>基礎設施投資</strong>：結合現有資產、網絡和客戶覆蓋，提供市場上最可信的端到端供應鏈解決方案</li></ul><h2 id="綠色轉型與船隊更新" tabindex="-1">綠色轉型與船隊更新 <a class="header-anchor" href="#綠色轉型與船隊更新" aria-label="Permalink to &quot;綠色轉型與船隊更新&quot;">​</a></h2><ul><li><strong>甲醇雙燃料船舶</strong>：大量投資甲醇動力船舶訂單，開發綠色燃料基礎設施</li><li><strong>淨零目標</strong>：承諾2040年實現全船隊溫室氣體淨零排放</li><li><strong>Next Boxship訂單</strong>：2025年訂購8艘18,600 TEU新型雙燃料船舶，並持續擴大船隊規模</li></ul><h2 id="聯盟合作-gemini-cooperation" tabindex="-1">聯盟合作：Gemini Cooperation <a class="header-anchor" href="#聯盟合作-gemini-cooperation" aria-label="Permalink to &quot;聯盟合作：Gemini Cooperation&quot;">​</a></h2><ul><li><strong>合作伙伴</strong>：2025年2月與赫伯羅特（Hapag-Lloyd）成立Gemini Cooperation</li><li><strong>規模</strong>：約290艘船舶，總運力340萬TEU（Maersk佔60%，Hapag-Lloyd佔40%）</li><li><strong>目標</strong>：關鍵航線準點率超過90%，顯著高於行業歷史平均水平</li><li><strong>市場佔有率</strong>：2025年約21.5%-22%的全球貨櫃運力市場份額</li></ul><h2 id="_2026年展望" tabindex="-1">2026年展望 <a class="header-anchor" href="#_2026年展望" aria-label="Permalink to &quot;2026年展望&quot;">​</a></h2><p>Maersk在2025財年表現強勁，2026年重點投資綠色物流和供應鏈整合。Gemini Cooperation的運作將進一步強化其服務可靠性和全球網絡覆蓋。</p><hr><p><strong>資料來源</strong>：Freightender (2025)、TNS Logistics (2026)、Marine Link (2026)、Logistics Viewpoints (2026-04)、Maersk官方新聞稿</p>',14)])])}const c=r(i,[["render",n]]);export{d as __pageData,c as default};
